          ((pin >= XBAR_NON_GPIO_MIN_CNT) && (pin <= XBAR_NON_GPIO_MAX_CNT)));

    //
    // Write the requested pin to the appropriate input select register.
    //
    HWREGH(base + INPUT_XBAR_O_INPUTSELECT((uint32_t)input)) = pin;
}

{
