    {
        HWREG(base + INPUT_XBAR_O_INPUTSELECTLOCK1) |= 1UL << (uint16_t)input;
    }
    else
    {
        HWREG(base + INPUT_XBAR_O_INPUTSELECTLOCK2) |= 1UL <<
                                                    ((uint16_t)input - 32U);
    }
}

